from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager, jwt_required, create_access_token
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "secret"  # Change this to a more secure key in production
jwt = JWTManager(app)

users = {}

@app.route("/register", methods=["POST"])
def register():
    data = request.get_json()
    if "username" not in data or "password" not in data:
        return jsonify({"error": "Both username and password are required"}), 400
    pw_hash = generate_password_hash(data["password"])
    user_id = len(users) + 1
    users[user_id] = {"username": data["username"], "password": pw_hash}
    return jsonify({"message": "User registered", "id": user_id}), 201

@app.route("/login", methods=["POST"])
def login():
    data = request.get_json()
    if "username" not in data or "password" not in data:
        return jsonify({"error": "Both username and password are required"}), 400
    if data["username"] not in users or not check_password_hash(users[data["username"]]["password"], data["password"]):
        return jsonify({"error": "Invalid credentials"}), 401
    access_token = create_access_token(identity=data["username"])
    return jsonify({"token": access_token}), 200

@app.route("/profile", methods=["GET"])
@jwt_required()
def profile():
    current_user = request.identity.username
    user = users.get(current_user)
    if user:
        return jsonify({"id": current_user, "username": user["username"]})
    else:
        return jsonify({"error": "Invalid token"}), 401

if __name__ == "__main__":
    app.run(debug=True)
